[Form]
public class ETGSalesEditLines extends FormRun
{
    Common      tableRecord; //Added by Rajat Dubey 09/05/2025
}

/// <summary>
/// Abhinav - 30-01-2025
/// </summary>
public Void createJournal(ETGSalesEditLines _ETGSalesEditLines)
{
    #OCCRetryCount
    Ledgerjournalname                          ledgerjournalname;
    LedgerjournalTable                         LedgerjournalTable;
    LedgerjournalTrans                         LedgerjournalTrans;
    NumberSeq                                  numberSeq;
    DimensionAttribute                         dimBusinessUnitAttribute , dimProfitCenterAttribute ;
    DimensionAttributeValue                    dimAttributeBusinessUnitValue;
    DimensionDefault                           defaultDimension;
    DimensionAttributeValueSetItem             dimensionAttributeValueSetItem;
    DimensionDynamicAccount                    ledgerDim;
    Currency                                   currencydet;
    DimensionAttributeValueSetStorage          dimStorage = new DimensionAttributeValueSetStorage();
    SalesTable                                 salestable = SalesTable::find(_ETGSalesEditLines.SalesId);
    //SalesParameters                            salesparameters = SalesParameters::find();

    ETGACFParameters                           ETGACFParameters = ETGACFParameters::find();



    if(ETGACFParameters.CreditJournalNameSales == '' || ETGACFParameters.DebitJournalNameSales == '')
    {
        throw error(strFmt('@ETG_New:ETGJournalNameNotInParameter'));
    }

    if(ETGACFParameters::find().MainAccountForCrDeJournalCreation == '')
    {
        throw error('@ETG_New:ETGMainAccountNotAvailable');
    }

    if( _ETGSalesEditLines.IsCrDeJournalCreated == NoYes::Yes)
    {
        throw error(strFmt('@ETG_New:ETGCrDeJournalAvailable',_ETGSalesEditLines.CrDeJournalNum));
    }

    try
    {

        if(_ETGSalesEditLines.RecId && ETGACFParameters::find().EnablePTBFContractsSales == NoYes::Yes)
        {

            SalesLine SalesLineupd;

            select SalesLineupd where SalesLineupd.SalesId == _ETGSalesEditLines.SalesId
                    && SalesLineupd.DefaultDimension == _ETGSalesEditLines.ETGRefDefaultDimension;

            if(_ETGSalesEditLines.ActualUnitPrice > SalesLineupd.SalesPrice)
            {
                select ledgerjournalname where ledgerjournalname.JournalName ==  ETGACFParameters.DebitJournalNameSales;
            }
            else
            {
                select ledgerjournalname where ledgerjournalname.JournalName ==  ETGACFParameters.CreditJournalNameSales;
            }

            //select ledgerjournalname where ledgerjournalname.JournalName ==  salesparameters.ETGJournalName;

            ttsBegin;
            LedgerjournalTable.clear();
            LedgerjournalTable.initValue();
            LedgerjournalTable.JournalName =  ledgerjournalname.JournalName;
            LedgerjournalTable.initFromLedgerJournalName();
            LedgerjournalTable.JournalNum  =  JournalTableData::newTable(LedgerjournalTable).nextJournalId();
            LedgerjournalTable.Name = 'Journal for '+_ETGSalesEditLines.SalesId;
            LedgerjournalTable.JournalType = LedgerJournalType::Daily;
            LedgerjournalTable.ETGIsCrDeJournal = NoYes::Yes;
            LedgerjournalTable.insert();

            if(ledgerjournalname)
            {

                numberSeq =  NumberSeq::newGetVoucherFromId((ledgerjournalname.NumberSequenceTable));
                LedgerjournalTrans.clear();
                LedgerjournalTrans.initValue();
                LedgerjournalTrans.Voucher      =   numberSeq.voucher();
                LedgerjournalTrans.JournalNum   =   LedgerjournalTable.JournalNum;
                LedgerjournalTrans.AccountType  =   LedgerJournalACType::Cust;
                LedgerjournalTrans.Company      =   curext();


                LedgerjournalTrans.parmAccount(salestable.InvoiceAccount,LedgerjournalTrans.AccountType);
                LedgerjournalTrans.CurrencyCode =  salestable::find(salestable.SalesId).CurrencyCode;//VendTable::find(salestable.InvoiceAccount).Currency;
                LedgerjournalTrans.TransDate    =  systemDateGet();
                LedgerjournalTrans.initForCurrency( LedgerjournalTable);
                LedgerjournalTrans.Txt          =   LedgerjournalTable.Name;
                LedgerjournalTrans.DefaultDimension  = salestable.DefaultDimension;
                LedgerjournalTrans.TransactionType         =   LedgerTransType::GeneralJournal;


                LedgerjournalTrans.LedgerDimension          = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber
                    (salestable.InvoiceAccount,LedgerJournalACType::Cust);



                LedgerjournalTrans.OffsetAccountType  =  LedgerJournalACType::Ledger;//ledgerjournalname.OffsetAccountType;//


                RecId ledgerDimension = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber
                    (ETGACFParameters::find().MainAccountForCrDeJournalCreation,LedgerJournalACType::Ledger);

                LedgerjournalTrans.OffsetLedgerDimension = ledgerjournalname.OffsetLedgerDimension; //ETGJournalCreateService::getLedgerDimension(con, '');
                LedgerjournalTrans.OffsetLedgerDimension = LedgerDimensionFacade::ServiceCreateLedgerDimension(ledgerDimension, salestable.DefaultDimension);


                LedgerjournalTrans.OffsetDefaultDimension = salestable.DefaultDimension;

                LedgerjournalTrans.Approved                 = NoYes::Yes;
                LedgerjournalTrans.Approver                 = HcmWorker::userId2Worker(curuserid());
                LedgerjournalTrans.DocumentNum              = _ETGSalesEditLines.SalesId;
                LedgerjournalTrans.Invoice                  = 'I-'+ salestable.SalesId+'-';//+ salestable.ParmId;
                LedgerjournalTrans.DocumentDate             = LedgerjournalTrans.Transdate;





                real Priceunit = SalesLineupd.salesprice ;

                if(SalesLineupd.LineDisc)
                {
                    Priceunit = Priceunit - SalesLineupd.LineDisc;
                }

                Amount AmountInCrDeNote = ( _ETGSalesEditLines.ActualUnitPrice - Priceunit ) * SalesLineupd.salesqty;

                if(SalesLineupd.LinePercent)
                {
                    AmountInCrDeNote = ( AmountInCrDeNote * (100 - SalesLineupd.LinePercent) ) / 100 ;
                }

                if(_ETGSalesEditLines.ActualUnitPrice > SalesLineupd.SalesPrice)
                {
                    LedgerjournalTrans.AmountCurDebit = abs(AmountInCrDeNote);
                }
                else  if(_ETGSalesEditLines.ActualUnitPrice < SalesLineupd.SalesPrice )
                {
                    LedgerjournalTrans.AmountCurCredit    =  abs(AmountInCrDeNote);
                }

                LedgerjournalTrans.insert();

                //if(salestable)
                //{
                //    salestable.selectForUpdate(true);
                //    salestable.IsCrDeJournalCreated = NoYes::Yes;
                //    salestable.CrDeJournalNum = LedgerjournalTable.JournalNum;
                //    salestable.CrDeJournalAmount = abs(AmountInCrDeNote);
                //    salestable.doUpdate();
                //}

                SalesLine saleslineloop;
                while select saleslineloop
                    where saleslineloop.SalesId == salestable.SalesId
                    && saleslineloop.DefaultDimension ==  _ETGSalesEditLines.ETGRefDefaultDimension
                {
                    saleslineloop.selectForUpdate(true);
                    saleslineloop.IsCrDeJournalCreated = NoYes::Yes;
                    saleslineloop.CrDeJournalNum = LedgerjournalTable.JournalNum;
                    saleslineloop.CrDeJournalAmount = abs(AmountInCrDeNote);
                    saleslineloop.doUpdate();
                }


                _ETGSalesEditLines.selectForUpdate(true);
                _ETGSalesEditLines.IsCrDeJournalCreated = NoYes::Yes;
                _ETGSalesEditLines.CrDeJournalNum = LedgerjournalTable.JournalNum;
                _ETGSalesEditLines.CrDeJournalAmount =  abs(AmountInCrDeNote);
                _ETGSalesEditLines.doUpdate();

            }

            ttscommit;

            info(strFmt('@ETG_New:ETGCrDeJournalCreated',LedgerjournalTable.JournalNum));

        }

    }
    catch(Exception::Error)
    {
        throw error('@ETG_New:ETGCrDeJournalCreationFailed');
    }
    catch(Exception::Deadlock)
    {
        retry;
    }
    catch(Exception::UpdateConflict)
    {
        if(appl.ttsLevel()==0)
        {
            if(xSession::currentRetryCount()>=#RetryNum)
            {
                throw exception::UpdateConflictNotRecovered;
            }
            else
            {
                retry;
            }
        }
        else
        {
            throw exception::UpdateConflict;
        }
    }
}

/// <summary>
/// CS Rajat Dubey 09/05/2025
/// </summary>
public void init()
{
    super();

    tableRecord = this.args().record();
}

/// <summary>
/// Abhinav - 30-01-2025
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = super();

    if(ETGACFParameters::find().EnablePTBFContractsSales == NoYes::Yes)
    {
        ETGSalesEditLines saleseditlines = ETGSalesEditLines_ds.cursor();
        FormRun formRun = ETGSalesEditLines_ds.formRun();

        SalesLine salesLine;

        select firstonly salesLine
            where salesLine.SalesId == saleseditlines.SalesId
            && salesLine.DefaultDimension == saleseditlines.ETGRefDefaultDimension;

        if(saleseditlines.Remain == 0 && salesLine.ETGPriceTolerance != 0 && saleseditlines.IsCrDeJournalCreated == NoYes::No)
        {
            formRun.design().controlName(formcontrolstr(ETGSalesEditLines,ETGSalesEditLines_ActualUnitPrice)).allowEdit(True);
        }
        else
        {
            formRun.design().controlName(formcontrolstr(ETGSalesEditLines,ETGSalesEditLines_ActualUnitPrice)).allowEdit(false);
        }

        //if(saleseditlines.IsCrDeJournalCreated == NoYes::Yes)
        //{
        //    formRun.design().controlName(formcontrolstr(ETGSalesEditLines,ETGSalesEditLines_ActualUnitPrice)).allowEdit(false);
        //}
        //else
        //{
        //    formRun.design().controlName(formcontrolstr(ETGSalesEditLines,ETGSalesEditLines_ActualUnitPrice)).allowEdit(true);
        //}
    }

    return ret;
}

/// <summary>
/// Abhinav - 30-01-2025
/// </summary>
public display int displayAmountReceivable(ETGSalesEditLines _etgSaleseditlines)
{

    if(ETGACFParameters::find().EnablePTBFContractsSales == NoYes::Yes && _etgSaleseditlines.InvoiceAmount)
    {
        if(_etgSaleseditlines.ActualUnitPrice < _etgSaleseditlines.SalesPrice)
        {
            return _etgSaleseditlines.InvoiceAmount - _etgSaleseditlines.CrDeJournalAmount;
        }
        else
        {
            return _etgSaleseditlines.InvoiceAmount + _etgSaleseditlines.CrDeJournalAmount;
        }

    }

    return 0;

}

/// <summary>
/// CS Rajat Dubey 09/05/2025
/// </summary>
public void executeQuery()
{
    ETGSalesEditLines salesEditLinesLoc = ETGSalesEditLines::findRecId(tableRecord.RecId);
    if(salesEditLinesLoc)
    {
        this.queryBuildDataSource().clearDynalinks();
        this.queryBuildDataSource().clearLinks();
        this.queryBuildDataSource().clearRanges();
        this.queryBuildDataSource().addRange(fieldnum(ETGSalesEditLines,RecId)).value(queryValue(tableRecord.RecId));
    }
    super();
}
