/// <summary>
///
/// </summary>
public display real displayCreditDebitAmount(ETGSalesEditLinesOverview _etgSalesEditLinesOverview)
{
    ETGSalesEditLines etgSaleseditlineSum;
    select sum(CrDeJournalAmount) from etgSaleseditlineSum
        where etgSaleseditlineSum.PackingSlipId == _etgSalesEditLinesOverview.PackingSlipId;

    return etgSaleseditlineSum.CrDeJournalAmount;

}

public display int displayAmountReceivableOverview(ETGSalesEditLinesOverview _etgSalesEditLinesOverview)
{
    ETGSalesEditLines etgSaleseditlineSum;
    select sum(CrDeJournalAmount) from etgSaleseditlineSum
        where etgSaleseditlineSum.PackingSlipId == _etgSalesEditLinesOverview.PackingSlipId;

    return _etgSalesEditLinesOverview.InvoiceAmount - etgSaleseditlineSum.CrDeJournalAmount;
}

/// <summary>
/// CS Rajat Dubey 09/05/2025
/// </summary>
public void executeQuery()
{
    ETGSalesEditLines salesEditLinesLoc = ETGSalesEditLines::findRecId(tableRecord.RecId);
    if(salesEditLinesLoc)
    {
        this.queryBuildDataSource().clearDynalinks();
        this.queryBuildDataSource().clearLinks();
        this.queryBuildDataSource().clearRanges();
        this.queryBuildDataSource().addRange(fieldnum(ETGSalesEditLinesOverview,PackingSlipId)).value(queryValue(salesEditLinesLoc.PackingSlipId));
    }
    super();
}
