/// <summary>
/// Abhinav 30-01-2025
/// </summary>
public void clicked()
{
    super();

    if(ETGACFParameters::find().EnablePTBFContractsSales == NoYes::Yes)
    {
        ETGSalesEditLines saleseditelines = ETGSalesEditLines_ds.cursor();

        if(saleseditelines.ActualUnitPrice == saleseditelines.SalesPrice)
        {
            throw Error("@ETG_New:ETGCrDeJournalUnitPriceSame");
        }

        if(saleseditelines.Remain != 0)
        {
            throw Error("@ETG_New:ETGCrDeRemainingQtyZero");
        }

        if(saleseditelines.Remain == 0 && saleseditelines.ActualUnitPrice == 0)
        {
            throw Error("@ETG_New:ETGCannotCreateCrDeJournal");
        }


        element.createJournal(saleseditelines);
    }

}

/// <summary>
/// Abhinav - 30-01-2025
/// </summary>
/// <returns></returns>
public boolean modified()
{
    boolean ret;

    ret = super();

    if(ETGACFParameters::find().EnablePTBFContractsSales == NoYes::Yes)
    {
        if(str2Num(this.valueStr()) <= 0.00)
        {
            throw error("@ETG_New:ETGCrDeActualUnitPriceZeroValue");
        }

        ETGSalesEditLines saleseditlines = ETGSalesEditLines_ds.cursor();
        SalesLine salesLine;

        select firstonly salesLine
            where salesLine.SalesId == saleseditlines.SalesId
            && salesLine.DefaultDimension == saleseditlines.ETGRefDefaultDimension;


        if(salesLine)
        {

            real checkPlus = 100 + salesLine.ETGPriceTolerance;
            real checkMinus = 100 - salesLine.ETGPriceTolerance;
            real ActualUnitprice = str2Num(this.valueStr());


            real a = (salesLine.SalesPrice * checkPlus) / 100;
            real b = (salesLine.SalesPrice * checkMinus) / 100;

            if(ActualUnitprice < b || ActualUnitprice > a)
            {
                throw error("@ETG_New:ETGCrDeActualUnitPrice");
            }

        }
    }


    return ret;
}
